import { Component, inject, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { AdminCasesService } from '../../../application/services/admin-cases.service';
import { TaskResolutionRequest } from '../../../application/models/backoffice.models';

@Component({
  selector: 'bo-task-resolution',
  templateUrl: './task-resolution.component.html',
  styleUrls: ['./task-resolution.component.css']
})
export class TaskResolutionComponent implements OnInit {
  private readonly adminCasesService = inject(AdminCasesService);
  private readonly route = inject(ActivatedRoute);
  readonly router = inject(Router);
  private readonly fb = inject(FormBuilder);

  resolutionForm: FormGroup = this.fb.group({
    action: ['approve', Validators.required],
    notes: ['', Validators.required]
  });

  caseId = '';
  taskId = '';
  isLoading = false;
  success = false;

  actionOptions = [
    { value: 'approve', label: 'Aprobar' },
    { value: 'reject', label: 'Rechazar' },
    { value: 'request_amendment', label: 'Solicitar Subsanacion' },
    { value: 'reassign', label: 'Reasignar' }
  ];

  ngOnInit(): void {
    this.caseId = this.route.snapshot.parent?.paramMap.get('id') || '';
    this.taskId = this.route.snapshot.paramMap.get('taskId') || '';
  }

  onSubmit(): void {
    if (this.resolutionForm.invalid) return;

    this.isLoading = true;
    const request: TaskResolutionRequest = this.resolutionForm.value;

    this.adminCasesService.resolveTask(this.caseId, this.taskId, request).subscribe({
      next: () => {
        this.success = true;
        this.isLoading = false;
        setTimeout(() => {
          this.router.navigate(['/cases', this.caseId]);
        }, 2000);
      },
      error: () => {
        this.isLoading = false;
      }
    });
  }
}
<div class="max-w-2xl mx-auto">
  <div class="bg-white rounded-lg shadow p-6">
    <h2 class="text-xl font-bold text-gray-900 mb-6">Resolver Tarea</h2>

    <div *ngIf="success" class="mb-4 p-4 bg-green-50 border border-green-200 text-green-700 rounded-md">
      Tarea resuelta correctamente. Redirigiendo...
    </div>

    <form [formGroup]="resolutionForm" (ngSubmit)="onSubmit()">
      <div class="mb-4">
        <label for="action" class="block text-sm font-medium text-gray-700 mb-1">
          Accion
        </label>
        <select
          id="action"
          formControlName="action"
          class="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option *ngFor="let opt of actionOptions" [value]="opt.value">{{ opt.label }}</option>
        </select>
      </div>

      <div class="mb-6">
        <label for="notes" class="block text-sm font-medium text-gray-700 mb-1">
          Observaciones
        </label>
        <textarea
          id="notes"
          formControlName="notes"
          rows="4"
          class="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          placeholder="Añade observaciones sobre esta resolucion..."
        ></textarea>
      </div>

      <div class="flex justify-end gap-3">
        <button
          type="button"
          (click)="router.navigate(['/cases', caseId])"
          class="px-4 py-2 border border-gray-300 text-gray-700 text-sm font-medium rounded-md hover:bg-gray-50"
        >
          Cancelar
        </button>
        <button
          type="submit"
          [disabled]="isLoading || resolutionForm.invalid"
          class="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-md hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <span *ngIf="!isLoading">Confirmar Resolucion</span>
          <span *ngIf="isLoading">Procesando...</span>
        </button>
      </div>
    </form>
  </div>
</div>
